  1	import React, { FC } from 'react';
  2	
  3	import {
  4	  modelToGroupVersionKind,
  5	  NamespaceModel,
  6	  NodeModel,
  7	  PodModel,
  8	  VirtualMachineInstanceModelGroupVersionKind,
  9	} from '@kubevirt-ui/kubevirt-api/console';
 10	import { V1VirtualMachine, V1VirtualMachineInstance } from '@kubevirt-ui/kubevirt-api/kubevirt';
 11	import OwnerDetailsItem from '@kubevirt-utils/components/OwnerDetailsItem/OwnerDetailsItem';
 12	import VirtualMachineDescriptionItem from '@kubevirt-utils/components/VirtualMachineDescriptionItem/VirtualMachineDescriptionItem';
 13	import { documentationURL } from '@kubevirt-utils/constants/documentation';
 14	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 15	import { getName, getNamespace } from '@kubevirt-utils/resources/shared';
 16	import { NO_DATA_DASH } from '@kubevirt-utils/resources/vm/utils/constants';
 17	import { getVMIPod } from '@kubevirt-utils/resources/vmi';
 18	import {
 19	  K8sResourceCommon,
 20	  K8sVerb,
 21	  ResourceLink,
 22	  useAccessReview,
 23	} from '@openshift-console/dynamic-plugin-sdk';
 24	import { Card, CardBody, CardTitle, DescriptionList, Divider } from '@patternfly/react-core';
 25	
 26	import './virtual-machines-overview-tab-general.scss';
 27	
 28	type VirtualMachinesOverviewTabGeneralProps = {
 29	  pods: K8sResourceCommon[];
 30	  vm: V1VirtualMachine;
 31	  vmi: V1VirtualMachineInstance;
 32	};
 33	
 34	const VirtualMachinesOverviewTabGeneral: FC<VirtualMachinesOverviewTabGeneralProps> = ({
 35	  pods,
 36	  vm,
 37	  vmi,
 38	}) => {
 39	  const { t } = useKubevirtTranslation();
 40	  const [canGetNode] = useAccessReview({
 41	    namespace: vm?.metadata?.namespace,
 42	    resource: NodeModel.plural,
 43	    verb: 'get' as K8sVerb,
 44	  });
 45	  const pod = getVMIPod(vmi, pods);
 46	
 47	  return (
 48	    <div className="VirtualMachinesOverviewTabGeneral--main">
 49	      <Card>
 50	        <CardTitle className="text-muted">{t('General')}</CardTitle>
 51	        <Divider />
 52	        <CardBody isFilled>
 53	          <DescriptionList className="pf-v6-c-description-list" isHorizontal>
 54	            <VirtualMachineDescriptionItem
 55	              bodyContent={t(
 56	                'Namespace defines the space within which each name must be unique. An empty namespace is equivalent to the "default" namespace, but "default" is the canonical representation. Not all objects are required to be scoped to a namespace - the value of this field for those objects will be empty. Must be a DNS_LABEL. Cannot be updated. ',
 57	              )}
 58	              descriptionData={
 59	                <ResourceLink
 60	                  groupVersionKind={modelToGroupVersionKind(NamespaceModel)}
 61	                  name={vm?.metadata?.namespace}
 62	                />
 63	              }
 64	              breadcrumb="VirtualMachine.metadata.namespace"
 65	              descriptionHeader={t('Namespace')}
 66	              isPopover
 67	              moreInfoURL={documentationURL.NAMESPACE_DOC}
 68	            />
 69	            {canGetNode && (
 70	              <VirtualMachineDescriptionItem
 71	                descriptionData={
 72	                  vmi?.status?.nodeName ? (
 73	                    <ResourceLink
 74	                      groupVersionKind={modelToGroupVersionKind(NodeModel)}
 75	                      name={vmi?.status?.nodeName}
 76	                    />
 77	                  ) : (
 78	                    NO_DATA_DASH
 79	                  )
 80	                }
 81	                descriptionHeader={t('Node')}
 82	              />
 83	            )}
 84	            <VirtualMachineDescriptionItem
 85	              descriptionData={
 86	                vmi?.metadata?.name ? (
 87	                  <ResourceLink
 88	                    groupVersionKind={VirtualMachineInstanceModelGroupVersionKind}
 89	                    name={vmi?.metadata?.name}
 90	                    namespace={vmi?.metadata?.namespace}
 91	                  />
 92	                ) : (
 93	                  NO_DATA_DASH
 94	                )
 95	              }
 96	              descriptionHeader={t('VirtualMachineInstance')}
 97	            />
 98	            <VirtualMachineDescriptionItem
 99	              descriptionData={
100	                pod?.metadata?.name ? (
101	                  <ResourceLink
102	                    groupVersionKind={modelToGroupVersionKind(PodModel)}
103	                    name={getName(pod)}
104	                    namespace={getNamespace(pod)}
105	                  />
106	                ) : (
107	                  NO_DATA_DASH
108	                )
109	              }
110	              descriptionHeader={t('Pod')}
111	            />
112	            <OwnerDetailsItem obj={vm} />
113	          </DescriptionList>
114	        </CardBody>
115	      </Card>
116	    </div>
117	  );
118	};
119	
120	export default VirtualMachinesOverviewTabGeneral;

